abstract class SecureSignatureProvider {
  Future<String> createSignature({
    required String payload,
    required String timestamp,
  });
}

class HmacSha256SignatureProvider implements SecureSignatureProvider {
  final String secret;

  const HmacSha256SignatureProvider(this.secret);

  @override
  Future<String> createSignature({
    required String payload,
    required String timestamp,
  }) async {
    final data = utf8.encode('$timestamp.$payload');
    final key = utf8.encode(secret);
    return Hmac(sha256, key).convert(data).toString();
  }
}

