class WalletBridge {
  final MethodChannel _channel;

  WalletBridge({String channelName = 'payment_wallet_bridge'})
      : _channel = MethodChannel(channelName);

  Future<bool> isWalletAvailable(MobileWalletType type) async {
    final result = await _channel.invokeMethod<bool>('isWalletAvailable', {
      'wallet_type': type.name,
    });
    return result ?? false;
  }

  Future<WalletPaymentToken> requestPaymentToken(
    WalletPaymentRequest request,
  ) async {
    final result = await _channel.invokeMapMethod<String, dynamic>(
      'requestPaymentToken',
      request.toJson(),
    );
    if (result == null) {
      throw const PaymentException(
        PaymentErrorCode.platform,
        'Wallet token result is empty',
      );
    }
    return WalletPaymentToken.fromJson(Map<String, dynamic>.from(result));
  }
}

