class InAppPurchaseService {
  final PaymentConfig config;
  final PaymentGatewayClient gatewayClient;
  final InAppPurchase _iap = InAppPurchase.instance;

  StreamSubscription<List<PurchaseDetails>>? _purchaseSubscription;
  final StreamController<PurchaseVerificationResult> _verifiedController =
      StreamController.broadcast();
  final StreamController<PurchaseDetails> _purchaseUpdateController =
      StreamController.broadcast();
  final StreamController<PaymentException> _errorController =
      StreamController.broadcast();

  bool _initialized = false;
  bool _isAvailable = false;

  InAppPurchaseService({
    required this.config,
    required this.gatewayClient,
  });

  Stream<PurchaseVerificationResult> get verifiedPurchases =>
      _verifiedController.stream;

  Stream<PurchaseDetails> get purchaseUpdates => _purchaseUpdateController.stream;

  Stream<PaymentException> get errors => _errorController.stream;

  bool get isAvailable => _isAvailable;

  Future<void> initialize() async {
    if (_initialized) return;
    _isAvailable = await _iap.isAvailable();
    if (!_isAvailable) {
      throw const PaymentException(
        PaymentErrorCode.unavailable,
        'In-app purchase store is unavailable',
      );
    }
    _purchaseSubscription = _iap.purchaseStream.listen(
      _onPurchaseUpdates,
      onError: (Object error) {
        final ex = PaymentException(
          PaymentErrorCode.platform,
          'Purchase stream error',
          error,
        );
        _errorController.add(ex);
      },
      onDone: () {},
      cancelOnError: false,
    );
    _initialized = true;
  }

  Future<ProductCatalogResult> queryProducts() async {
    await initialize();
    final response = await _iap.queryProductDetails(config.allProductIds);
    if (response.error != null) {
      throw PaymentException(
        PaymentErrorCode.platform,
        response.error!.message,
        response.error,
      );
    }
    return ProductCatalogResult(
      products: response.productDetails,
      notFoundIds: response.notFoundIDs,
    );
  }

  Future<void> buyConsumable({
    required ProductDetails product,
    String? applicationUserName,
    bool autoConsume = true,
  }) async {
    await initialize();
    final param = PurchaseParam(
      productDetails: product,
      applicationUserName: applicationUserName,
    );
    final ok = await _iap.buyConsumable(
      purchaseParam: param,
      autoConsume: autoConsume,
    );
    if (!ok) {
      throw const PaymentException(
        PaymentErrorCode.platform,
        'Failed to start consumable purchase',
      );
    }
  }

  Future<void> buyNonConsumable({
    required ProductDetails product,
    String? applicationUserName,
  }) async {
    await initialize();
    final param = PurchaseParam(
      productDetails: product,
      applicationUserName: applicationUserName,
    );
    final ok = await _iap.buyNonConsumable(purchaseParam: param);
    if (!ok) {
      throw const PaymentException(
        PaymentErrorCode.platform,
        'Failed to start non-consumable purchase',
      );
    }
  }

  Future<void> restorePurchases({String? applicationUserName}) async {
    await initialize();
    await _iap.restorePurchases(applicationUserName: applicationUserName);
  }

  Future<PurchaseVerificationResult> verifyPurchase(
    PurchaseDetails purchase,
  ) async {
    final receipt = _extractReceiptData(purchase);
    if (receipt.isEmpty) {
      throw const PaymentException(
        PaymentErrorCode.verificationFailed,
        'Receipt data is missing',
      );
    }
    final result = await gatewayClient.verifyPurchase(
      platform: defaultTargetPlatform == TargetPlatform.iOS ? 'ios' : 'android',
      productId: purchase.productID,
      transactionId: purchase.purchaseID ?? '',
      receiptData: receipt,
    );
    return PurchaseVerificationResult(
      purchase: purchase,
      verification: result,
    );
  }

  Future<void> _onPurchaseUpdates(List<PurchaseDetails> purchases) async {
    for (final purchase in purchases) {
      _purchaseUpdateController.add(purchase);

      if (purchase.status == PurchaseStatus.error) {
        _errorController.add(
          PaymentException(
            PaymentErrorCode.platform,
            purchase.error?.message ?? 'Purchase error',
            purchase.error,
          ),
        );
        if (purchase.pendingCompletePurchase) {
          await _iap.completePurchase(purchase);
        }
        continue;
      }

      if (purchase.status == PurchaseStatus.canceled) {
        _errorController.add(
          const PaymentException(
            PaymentErrorCode.declined,
            'Purchase cancelled',
          ),
        );
        if (purchase.pendingCompletePurchase) {
          await _iap.completePurchase(purchase);
        }
        continue;
      }

      if (purchase.status == PurchaseStatus.purchased ||
          purchase.status == PurchaseStatus.restored) {
        try {
          final verified = await verifyPurchase(purchase);
          _verifiedController.add(verified);
        } catch (e) {
          _errorController.add(
            e is PaymentException
                ? e
                : PaymentException(
                    PaymentErrorCode.verificationFailed,
                    'Verification failed',
                    e,
                  ),
          );
        } finally {
          if (purchase.pendingCompletePurchase) {
            await _iap.completePurchase(purchase);
          }
        }
      }
    }
  }

  String _extractReceiptData(PurchaseDetails purchase) {
    if (purchase.verificationData.serverVerificationData.isNotEmpty) {
      return purchase.verificationData.serverVerificationData;
    }
    return purchase.verificationData.localVerificationData;
  }

  Future<void> dispose() async {
    await _purchaseSubscription?.cancel();
    await _verifiedController.close();
    await _purchaseUpdateController.close();
    await _errorController.close();
  }
}

class PaymentModule {
  final PaymentConfig config;
  late final PaymentGatewayClient gateway;
  late final InAppPurchaseService inAppPurchases;
  late final WalletBridge walletBridge;

  PaymentModule({
    required this.config,
    http.Client? httpClient,
    SecureSignatureProvider? signatureProvider,
  }) {
    gateway = PaymentGatewayClient(
      config: config,
      httpClient: httpClient,
      signatureProvider: signatureProvider,
    );
    inAppPurchases = InAppPurchaseService(
      config: config,
      gatewayClient: gateway,
    );
    walletBridge = WalletBridge(
      channelName: config.walletChannelName ?? 'payment_wallet_bridge',
    );
  }

  Future<void> initialize() async {
    await inAppPurchases.initialize();
  }

  Future<ProductCatalogResult> fetchCatalog() {
    return inAppPurchases.queryProducts();
  }

  Future<PaymentOrderResponse> createOrder(PaymentOrderRequest request) {
    return gateway.createOrder(request);
  }

  Future<PaymentResult> payWithWallet({
    required WalletPaymentRequest request,
  }) async {
    final available = await walletBridge.isWalletAvailable(request.walletType);
    if (!available) {
      throw const PaymentException(
        PaymentErrorCode.unavailable,
        'Requested wallet is not available',
      );
    }
    final token = await walletBridge.requestPaymentToken(request);
    return gateway.authorizeWalletPayment(
      request: request,
      token: token,
    );
  }

  Future<void> buyProduct(ProductDetails product) {
    final id = product.id;
    if (config.consumableProductIds.contains(id)) {
      return inAppPurchases.buyConsumable(product: product);
    }
    return inAppPurchases.buyNonConsumable(product: product);
  }

  Future<void> restorePurchases() {
    return inAppPurchases.restorePurchases();
  }

  Stream<PurchaseVerificationResult> get verifiedPurchases =>
      inAppPurchases.verifiedPurchases;

  Stream<PurchaseDetails> get purchaseUpdates =>
      inAppPurchases.purchaseUpdates;

  Stream<PaymentException> get errors => inAppPurchases.errors;

  Future<void> dispose() async {
    await inAppPurchases.dispose();
    gateway.dispose();
  }
}

class PaymentSecurity {
  static Map<String, String> pciSafeHeaders({
    required String publishableKey,
    String? clientVersion,
  }) {
    return {
      'X-Publishable-Key': publishableKey,
      if (clientVersion != null) 'X-Client-Version': clientVersion,
      'X-PCI-Mode': 'tokenized',
    };
  }

  static void assertNoSensitiveCardData(Map<String, dynamic> payload) {
    const blockedKeys = {
      'card_number',
      'pan',
      'cvv',
      'cvc',
      'expiry',
      'exp_month',
      'exp_year',
      'full_track_data',
      'pin',
    };
    for (final entry in payload.entries) {
      if (blockedKeys.contains(entry.key.toLowerCase())) {
        throw const PaymentException(
          PaymentErrorCode.invalidRequest,
          'Sensitive card data must not be handled by the client',
        );
      }
      if (entry.value is Map<String, dynamic>) {
        assertNoSensitiveCardData(entry.value as Map<String, dynamic>);
      }
    }
  }
}